#include<bits/stdc++.h>
#define hash myhasheeeeeee
using namespace std;
const int mod1=998244353,mod2=1e9+7;
long long base[1000010],hash[1000010];
char t[1000010];
void init(int n)
{
    base[0]=1;
    for(int i=1;i<=n;i++)
    {
        base[i]=base[i-1]*mod1%mod2;
    }
}
long long gethash(int l,int r)
{
    return ((hash[r]-hash[l-1]*base[r-l+1]%mod2)%mod2+mod2)%mod2;
}
int main()
{
    int n,m;
    scanf("%d%s",&n,t+1);
    m=n/2;
    init(n);
    int len=0,ans=0;
    for(int i=1;i<=n;i++)
    {
        hash[i]=(hash[i-1]*mod1%mod2+t[i])%mod2;
    }
    for(int i=m;i>=0;i--)
    {
        len=min(len+2,m-i);
        while(len>0&&gethash(i+1,i+len)!=gethash(n-i-len+1,n-i))
        {
            len--;
        }
        if(gethash(1,i)==gethash(n-i+1,n))
        {
            ans=max(ans,i+len);
        }
    }
    printf("%d",ans);
    return 0;
}
